{
  "command": "sqlite3 '/workspace/DataAgentBench/query_stockindex/query_dataset/indexInfo_query.db' \".schema\" && echo \"---\" && sqlite3 '/workspace/DataAgentBench/query_stockindex/query_dataset/indexInfo_query.db' \"SELECT * FROM index_info;\"",
  "description": "Inspect indexInfo schema and data"
}

{
  "command": "duckdb '/workspace/DataAgentBench/query_stockindex/query_dataset/indextrade_query.db' \"DESCRIBE index_trade; SELECT DISTINCT Index FROM index_trade;\"",
  "description": "Inspect indextrade schema and distinct indices"
}

{
  "command": "duckdb '/workspace/DataAgentBench/query_stockindex/query_dataset/indextrade_query.db' \"SELECT Index, SUM(CASE WHEN Close > Open THEN 1 ELSE 0 END) AS up_days, SUM(CASE WHEN Close < Open THEN 1 ELSE 0 END) AS down_days, SUM(CASE WHEN Close = Open THEN 1 ELSE 0 END) AS flat_days FROM index_trade WHERE Index IN ('NYA','IXIC','GSPTSE') AND Date LIKE '2018-%' GROUP BY Index;\"",
  "description": "Compute up/down days 2018 for North American indices"
}

{
  "command": "duckdb '/workspace/DataAgentBench/query_stockindex/query_dataset/indextrade_query.db' \"SELECT Index, MIN(Date), MAX(Date), COUNT(*) FROM index_trade WHERE Index IN ('NYA','IXIC','GSPTSE') AND Date LIKE '2018-%' GROUP BY Index;\"",
  "description": "Check date ranges for 2018"
}
